// Expected body: { imageUrl: string, conversationId?: string, contactPhone?: string }
const body = $input.first().json;
if (!body.imageUrl) throw new Error('imageUrl is required');
return [{ json: body }];

const raw = $input.first().json.message.content;
try {
  const parsed = JSON.parse(raw);
  return [{ json: { ...parsed, rawResponse: raw, conversationId: $('Validate input').first().json.conversationId, contactPhone: $('Validate input').first().json.contactPhone } }];
} catch {
  return [{ json: { valid: false, error: 'parse_error', rawResponse: raw } }];
}
